/*Side Nav Functions*/
var pause=0;
function openNav(obj) {
    console.log(obj);
    var width = $window.width();
    document.getElementById('mapName').innerHTML = obj[0];
    document.getElementById('myLocationMap').setAttribute('href', 'https://maps.google.com/?saddr=My+Location&daddr=' + obj[1] + ',' + obj[2]);
    $("#navHospCode").val(obj[3]);
    $("#bloodComponentType").val(11);
    getStockData(obj[3], "all", "11");
    getCampData(obj[3]);
    if (width >= 450)
        document.getElementById("mySidenav").style.width = "450px";
    else {
        document.getElementById("mySidenav").style.width = width + "px";
    }
}

function getStockData(hospCode, bloodGroupType, bloodComponent) {
    var url = '/BLDAHIMS/bloodbank/nearbyBB.cnt?hmode=GETSTOCKDETAILSMAP&hospitalCode=' + hospCode + '&bloodGroup=' + bloodGroupType + '&bloodComponent=' + bloodComponent;
    $.ajax({
        url: url,
        success: function(data) {
            console.log(data);
            data = data.replace(/'/g, "'");
            data = JSON.parse(data);
            console.log(data);
            if (data.data.length == 0) {
                $("#stockDetailsData").html("<p style='color:red'>Data not Available For your selection !</p>");
                return false;
            }
            $("#stockDetailsData").html("<p>" + data.data[0][3] + "<tr> <br><b style='color:red;'>Last Updated: </b>&nbsp;" + data.data[0][4] + "</tr></p>");
            console.log(data.data[0][3]);
            console.log("all coming data is" + data.data[0]);
        },
        error: function(data) {
            console.log(data);
        }
    });
}

function getCampData(hospCode) {
    var url = '/BLDAHIMS/bloodbank/nearbyBB.cnt?hmode=GETNEARBYCAMPS&hospitalCode=' + hospCode;
    $.ajax({
        url: url,
        success: function(data) {
            console.log(data);
            data = data.replace(/'/g, "'");
            data = JSON.parse(data);
            console.log(data);
            if (data.data.length == 0) {
                $("#campDetailsData").html("<p style='color:red'>No Data Available For your selection !</p>");
                return false;
            }
            var table = createCampTable(data.data, hospCode);
            var wrap = document.createElement('div');
            wrap.appendChild(table.cloneNode(true));
            $("#campDetailsData").html(wrap);
        },
        error: function(data) {
            console.log(data);
        }
    });
}

function createCampTable(jsonObj, hospCode) {
    var table = document.createElement("TABLE");
    table.className = "table table-condensed table-bordered";
    for (i = 0; i < jsonObj.length; i++) {
        var row = table.insertRow(-1);
        var cell1 = row.insertCell(0);
        var cell2 = row.insertCell(1);
        var cell3 = row.insertCell(2);
        var cell4 = row.insertCell(3);
        cell1.innerHTML = jsonObj[i][1].substring(1, 10);
        cell2.innerHTML = jsonObj[i][2];
        cell3.innerHTML = jsonObj[i][4];
        cell4.innerHTML = jsonObj[i][10];
    }
    var row = table.insertRow(0);
    var cell1 = row.insertCell(0);
    var cell2 = row.insertCell(1);
    var cell3 = row.insertCell(2);
    var cell4 = row.insertCell(3);
    cell1.innerHTML = "Date";
    cell2.innerHTML = "Time";
    cell3.innerHTML = "Address";
    cell4.innerHTML = "Register";
    var row = table.insertRow(-1);
    var cell = row.insertCell(0);
    cell.innerHTML = "<a href='/BLDAHIMS/bloodbank/campSchedule.cnt?GETNEARBYCAMPS&hospitalCode=" + hospCode + "'>Know More</a>";
    cell.colSpan = 4;
    return table;
}

function componentSelected(compValue) {
    var hospCode = $("#navHospCode").val();
    getStockData(hospCode, "all", compValue);
}

function closeNav() {
    document.getElementById("mySidenav").style.width = "0";
}
/*Ends here*/

function updateMapLocation() {
    $.ajax({
        url: "/BLDAHIMS/bloodbank/nearbyBB.cnt?hmode=FETCHLOCATION",
        success: function(data) {
            $.locations = data.replace(/'/g, "'");
        },
        async: false
    });
    $.locations = JSON.parse($.locations);
}

function updateMap()
{
    clearOverlays();
    for (i=0; i < $.locations.length; i++)
    {
        marker = new google.maps.Marker
        ({
            position: new google.maps.LatLng($.locations[i][1], $.locations[i][2]),
            map: $.mapvar
        });
        markersArray.push(marker);
        google.maps.event.addListener(marker, 'click', (function(marker, i)
        		{
                return function()
                {
                    $.infowindow.setContent($.locations[i][0]);
                    $.infowindow.open($.mapvar, marker);
                }
            })
            (marker, i));
    }
}

