/*Side Notifications*/
function notify(text) {	
    numsLen = 10, maxNum = 10, num = 0;
    if (nums.length < numsLen) {
        num = Math.round(Math.random() * maxNum);
        if (nums.indexOf(num) === -1) {
            notify1(num);
            nums.push(num);
        }
    } else {
        nums = [];
    }
}

function notify1(RandomNo) {
	
	if (langg!=null && langg==1)
	{
    switch (RandomNo) {
    case 10:
        text = "रक्त दान करें, जीवन बचाएं!";
        break;
    case 1:
        text = "एक मुस्कान उपहार, एक बूंद उपहार!";
        break;
    case 2:
        text = "हर रक्तदाता एक हीरो है!";
        break;
    case 3:
        text = "रक्त दें और स्वस्थ रहें।";
        break;
    case 4:
        text = "हर ड्रॉप मायने रखता है। आज रक्त दें।";
        break;
    case 5:
        text = "रक्त तीन दिनों में फिर से भरता है और एक जीवन भी बचाता है।";
        break;
    case 6:
        text = "ब्लड डोनर्स सनशाइन लाते हैं।";
    case 7:
        text = "रक्त का दान हानिरहित और सुरक्षित है।";
        break;
    case 8:
        text = " नियमित रक्तदाता बनें।";
        break;
    case 9:
        text = "दूसरे की नसों में एक रन के लिए जाएं।";
        break;
    default:
        text = " नियमित रक्तदाता बनें।";
    
       
    	}
    }
	
	else 
	{
	
    switch (RandomNo) {
    		
    
			case 10:
			text = "Donate Blood ,save lives!";
			break;
			case 1:
			text = "Gift a smile, gift a drop !";
			break;
			case 2:
			text = "Every Blood Donor is a HERO!";
			break;
			case 3:
			text = "Give blood and stay healthy.";
			break;
			case 4:
			text = "Every Drop Counts. Give Blood Today.";
			break;
			case 5:
			text = "Blood replenishes in three days and save a life too.";
			break;
			case 6:
			text = "Blood Donors bring Sunshine.";
			case 7:
			text = "Donation of blood is harmless and safe.";
			break;
			case 8:
			text = " Be a regular Blood Donor.";
			break;
			case 9:
			text = "Go for a run in another’s veins.";
			break;
			default:
			text = " Be a regular Blood Donor.";
			    
			    	
    	}
    }
    if ($window.width() > 960) {
        var $notification = $('<li />').text(text).css({
            'left': '320',
            'background-color': 'red'
        }).css('cursor', 'pointer').click(function() {
            window.location = "../donateblood.cnt";
            return false;
        });
        $notifications.append($notification);
        $notification.animate({
            left: 0
        }, 300, function() {
            $(this).delay(3000).animate({
                left: 320
            }, 200, function() {
                $(this).slideUp(100, function() {
                    $(this).remove()
                });
            });
        });
    }
}
