function getLocation() {
    if (navigator.geolocation) {
        navigator.geolocation.getCurrentPosition(showPosition, showError);
    } else {
        $(x).removeClass('label-info');
        $(x).addClass('label-danger');
        x.innerHTML = "Geolocation is not supported by this browser.";
        $('#lat').val("-1");
        $('#lon').val("-1");
    }
}

function geocodeLatLng(lat, lon) {
    var geocoder = new google.maps.Geocoder;
    var latlng = {
        lat: parseFloat(lat),
        lng: parseFloat(lon)
    };
    geocoder.geocode({
        'location': latlng
    }, function(results, status) {
        if (status === google.maps.GeocoderStatus.OK) {
            if (results[1]) {
                x.innerHTML = "Current Location: " +
                    results[1].formatted_address;
            } else if (results[0]) {
                x.innerHTML = "Current Location: " +
                    results[0].formatted_address;
            } else {
                window.alert('No results found');
            }
        } else {
            window.alert('Geocoder failed due to: ' + status);
        }
    });
}

function getLatLonBloodBankList(lat, lon, mode) {
    var table;
    var newURL = "/BLDAHIMS/bloodbank/nearbyBB.cnt?hmode=GETNEARBYBLOODBANKLOCATION&latitude=" +
        lat + "&longitude=" + lon+"&lang="+lang;
    $.ajax({
        url: newURL,
        success: function(data) {
            closeNav();
            $.locations = data.replace(/'/g, "\'");
            if ($.locations != "") {
                if (mode == "search") {
                	 $.ajax({
                         url: "/BLDAHIMS/bloodbank/campSchedule.cnt?hmode=FETCHACTIVELOCATIONS&bbDataType=1",
                         success: function(data) {
                             $.locations = data.replace(/'/g, "\'");
                             drawLocationOnMap();
                             mapSearchOnMap(lat, lon);
                             //$.mapvar.setCenter(delhi);
                             //$.mapvar.setZoom(5); /*var markerCluster = new MarkerClusterer($.mapvar, markersArray, {maxZoom: 9,imagePath: 'https://developers.google.com/maps/documentation/javascript/examples/markerclusterer/m'});*/
                         },
                         error: function(data) {}
                     });
                    
                }
                if (mode == "nearby") {
                    drawLocationOnMap();
                }
            }
            if ($.locations == "") {
                if (mode == "nearby") {
                    x.innerHTML = "Blood Banks Not Found For Your Location";
                    $(x).removeClass('label-info');
                    $(x).addClass('label-danger');
                }
                if (mode = "search") {
                    $("#bbWarning").show();
                }
            }
        },
        error: function(data) {}
    });
}


function showError(error) {
    var txt;
    $(x).removeClass('label-info');
    $(x).addClass('label-danger');
    switch (error.code) {
        case error.PERMISSION_DENIED:
            x.innerHTML = "User denied the request for Geolocation."
            txt = "User denied the request for Geolocation.";
            break;
        case error.POSITION_UNAVAILABLE:
            x.innerHTML = "Location information is unavailable."
            txt = "Location information is unavailable.";
            break;
        case error.TIMEOUT:
            x.innerHTML = "The request to get user location timed out."
            txt = "The request to get user location timed out.";
            break;
        case error.UNKNOWN_ERROR:
            x.innerHTML = "An unknown error occurred."
            txt = "An unknown error occurred.";
            break;
    }
    $('#lat').val("-1");$('#lon').val("-1");
    }


