function viewBloodBanks() {
    var lat = $("#lat").val();
    var lon = $("#lon").val();
    if (lat == "" || lon == "") {
        $("#locationWarning").show();
        return false;
    }
    $("#locationWarning").hide();
    getLatLonBloodBankList(lat, lon, "search");
}

function mapSearchOnMap(lat, lon) {
    if (typeof $.locations != 'undefined' && $.locations != '' && $.locations.length > 0) {
        console.log($.locations);
        //drawLocationOnMap();
        var LatLng = {
            lat: parseFloat(lat),
            lng: parseFloat(lon)
        };
        $.mapvar.setCenter(LatLng);
        $.mapvar.setZoom(10);
        $($(".mapButton")[0]).removeClass("selectedButton");
        $($(".mapButton")[1]).removeClass("selectedButton");
        goToByScroll("mapHeading");
        $("#bbWarning").hide();
    } else {
        $("#bbWarning").show();
    }
}

