/*Switching b/w tabs*/
function openInfo(evt, featureName) {
    // Declare all variables
    var i, tabcontent, tablinks;

    // Get all elements with class="tabcontent" and hide them
    tabcontent = document.getElementsByClassName("tabInfo");
    for (i = 0; i < tabcontent.length; i++) {
        tabcontent[i].style.display = "none";
    }

    // Get all elements with class="tablinks" and remove the class "active"
    tablinks = document.getElementsByClassName("infoLink");
    for (i = 0; i < tablinks.length; i++) {
        tablinks[i].className = tablinks[i].className.replace(" active", "");
    }

    // Show the current tab, and add an "active" class to the button that opened the tab
    document.getElementById(featureName).style.display = "block";
    evt.currentTarget.className += " active";
}

/*To Detect wheter browser support webp, and then take action accordingly*/ 
function initialiseImages() {
	
	/*Webp detection happening here*/
	 var hasWebP = (function() {
		    // some small (2x1 px) test images for each feature
		    var images = {
		        basic: "data:image/webp;base64,UklGRjIAAABXRUJQVlA4ICYAAACyAgCdASoCAAEALmk0mk0iIiIiIgBoSygABc6zbAAA/v56QAAAAA==",
		        lossless: "data:image/webp;base64,UklGRh4AAABXRUJQVlA4TBEAAAAvAQAAAAfQ//73v/+BiOh/AAA="
		    };

		    return function(feature) {
		        var deferred = $.Deferred();

		        $("<img>").on("load", function() {
		            // the images should have these dimensions
		            if(this.width === 2 && this.height === 1) {
		                deferred.resolve();
		            } else {
		                deferred.reject();
		            }
		        }).on("error", function() {
		            deferred.reject();
		        }).attr("src", images[feature || "basic"]);

		        return deferred.promise();
		    }
		})();
	
    var slider = document.getElementById("myCarousel");
    var images = slider.getElementsByTagName('img');
    
   
    hasWebP().then(function() {
    	 for (var i = 0; i < images.length; i++) {
    	        var src = images[i].getAttribute('data-src-webp');
    	        var datasrc = document.createAttribute('src');
    	        datasrc.value = src;
    	        images[i].setAttributeNode(datasrc);
    	        images[i].removeAttribute('data-src');
    	        images[i].removeAttribute('data-src-webp');
    	    }
    	 //loadGIF();
    }, function() {
    	 for (var i = 0; i < images.length; i++) {
 	        var src = images[i].getAttribute('data-src');
 	        var datasrc = document.createAttribute('src');
 	        datasrc.value = src;
 	        images[i].setAttributeNode(datasrc);
 	        images[i].removeAttribute('data-src');
 	        images[i].removeAttribute('data-src-webp');
 	    }
    	 //loadGIF();
    });
    
 
    
   
}

